- "mighty titans": refers to wealthy individuals; 
- "financial prowess": refers to high net worth in billions of dollars; 
- "land of Mexico": individuals who are from Mexico.

sql:
SELECT country_name
FROM countries
WHERE country_id = 0;

SELECT DISTINCT i.name
FROM individuals i
WHERE i.net_worth_bil > 10;

SELECT AVG(net_worth_bil) AS average_net_worth
FROM individuals
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'United States');

SELECT rank, net_worth_bil
FROM individuals
ORDER BY net_worth_bil DESC;

WITH avg_net_worth AS (
      SELECT AVG(net_worth_bil) AS avg_worth FROM individuals
  ),
  primary_individuals AS (
      SELECT individual_id FROM family_members WHERE relationship = 'Primary'
  )
  SELECT i.name
  FROM individuals i
  INNER JOIN primary_individuals pi ON i.individual_id = pi.individual_id
  WHERE i.net_worth_bil >= (SELECT avg_worth FROM avg_net_worth);

SELECT name 
FROM individuals 
WHERE individual_id IN (SELECT individual_id FROM net_worth_history);

